### 🐛 Current behavior

If you use getServerState outside of getStaticProps webpack throws this error:

```bash
warn  - ./node_modules/react-instantsearch-hooks-server/dist/es/getServerState.js
```

This throw the warning
```js
import { transformServerFlexibleContent } from '@lib/graphql/transformers';

export async function getStaticProps({ params }) {
  const Query = PageQuery();
  const staticProps = await getInitialProps(Query, { slug: params.slug });
  const {
    props: {
      pageProps: {
        flexibleContent: { flexible },
      },
    },
  } = staticProps;
  const path = routes.sellers.seller(params.slug);

  staticProps.props.pageProps.flexibleContent.flexible =
    await transformServerFlexibleContent(flexible, 'Seller', path);

  return staticProps;
}
```

This doesn't throw the warning
```js
export async function getStaticProps({ params }) {
  const Query = PageQuery();
  const staticProps = await getInitialProps(Query, { slug: params.slug });
  const {
    props: {
      pageProps: {
        flexibleContent: { flexible },
      },
    },
  } = staticProps;
  const path = routes.sellers.seller(params.slug);

  const transformServerFlexibleContent = (...params) => {
     // The implementation of the data transform
    const serverState = await getServerState(
      <Category
        title={title}
        filters={filters}
        url={path}
      />,
      { renderToString }
    );
    // ... more data transform
  }

  staticProps.props.pageProps.flexibleContent.flexible =
    await transformServerFlexibleContent(flexible, 'Seller', path);

  return staticProps;
}
```

### 🔍 Steps to reproduce

Extract getServerState logic to a function instead of use it directly in getStaticProps or getServerProps

### Live reproduction

I can't do it right now

### 💭 Expected behavior

The same behavior using getServerState inside of getStaticProps or getServerProps or in a function

